  "OLIVER": {
   "name": "OLIVER",
   "file": "station.zil",
   "line": 2551,
   "endLine": 2573,
   "desc": "Oliver",
   "ldesc": "A little \"sleeping\" robot named \"Oliver\" is lying here.",
   "fdesc": "There's a young-looking robot lying here, apparently having completed the\nfinal \"training\" phase of its construction. The wires for feeding it\ninformation have been removed, but it has not yet \"woken up.\" A dim memory\nfrom your old robotics text drifts through your mind: \"The incubation period\nbetween the training and 'birth' of a robot is two to twenty days, depending\non the complexity of the model.\" This particular model has the name\n\"Oliver\" engraved on its chestplate.",
   "loc": "ROBOT-SHOP",
   "flags": [
    "NARTICLEBIT",
    "VOWELBIT"
   ],
   "synonyms": [
    "OLIVER",
    "ROBOT"
   ],
   "adjectives": [
    "SMALL",
    "YOUNG"
   ],
   "action": "OLIVER-F",
   "descfcn": null,
   "contfcn": null,
   "globals": [],
   "pseudo": [],
   "otherProps": {
    "FLOYD-ASK-ABOUT": [
     "If we be here when Oliver wakes up, Floyd would like to teach\nOliver to play paddleball. Paddleball helped Floyd forget how lonely and\nscared he was until he found friends...like you."
    ],
    "PLATO-ASK-ABOUT": [
     "Ah, a new robot. Poor fellow; new robots are so mercilessly mistreated by\nthe older robots. Such is our lot."
    ]
   },
   "contents": [],
   "source": "<OBJECT OLIVER\n\t(IN ROBOT-SHOP)\n\t(DESC \"Oliver\")\n\t(FDESC ;\"so it'll get printed before other DESCs\"\n\"There's a young-looking robot lying here, apparently having completed the\nfinal \\\"training\\\" phase of its construction. The wires for feeding it\ninformation have been removed, but it has not yet \\\"woken up.\\\" A dim memory\nfrom your old robotics text drifts through your mind: \\\"The incubation period\nbetween the training and 'birth' of a robot is two to twenty days, depending\non the complexity of the model.\\\" This particular model has the name\n\\\"Oliver\\\" engraved on its chestplate.\")\n\t(LDESC \"A little \\\"sleeping\\\" robot named \\\"Oliver\\\" is lying here.\")\n\t(SYNONYM OLIVER ROBOT)\n\t(ADJECTIVE SMALL YOUNG)\n\t(FLAGS NARTICLEBIT VOWELBIT)\n\t(FLOYD-ASK-ABOUT\n\"If we be here when Oliver wakes up, Floyd would like to teach\nOliver to play paddleball. Paddleball helped Floyd forget how lonely and\nscared he was until he found friends...like you.\")\n\t(PLATO-ASK-ABOUT\n\"Ah, a new robot. Poor fellow; new robots are so mercilessly mistreated by\nthe older robots. Such is our lot.\")\n\t(ACTION OLIVER-F)>",
   "referencedBy": [
    "THIS-IS-IT",
    "FLOYD-F",
    "ROBOT-SHOP-F",
    "OLIVER-F"
   ]
  },
